arguments.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<ModelTrainerService>();

var app = builder.Build();

// Train the model at startup and register the prediction engine pool
var trainer = app.Services.GetRequiredService<ModelTrainerService>();
trainer.TrainAndSaveModel();

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.GetModelPath());

// Rebuild the service provider so the pool is available
var poolProvider = builder.Services.BuildServiceProvider();
var predictionPool = poolProvider.GetRequiredService<PredictionEnginePool<TicketInput, TicketPrediction>>();

app.MapPost("/api/predict", (TicketRequest request) =>
{
    var input = new TicketInput
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority
    };

    var prediction = predictionPool.Predict(input);

    string[] labels = ["Billing", "General", "Technical"];
    var confidence = new Dictionary<string, float>();
    for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
    {
        confidence[labels[i]] = prediction.Score[i];
    }

    return Results.Ok(new TicketResponse
    {
        PredictedCategory = prediction.Category,
        Confidence = confidence
    });
});

app.Run();

