using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

var builder = WebApplication.CreateBuilder(args);

// Train the model before building the app
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainResult = TrainModel(builder.Environment.ContentRootPath,
    loggerFactory.CreateLogger("ModelTraining"));

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainResult.ModelPath);

// Store the label names so the endpoint can map scores to categories
builder.Services.AddSingleton(trainResult.Labels);

var app = builder.Build();

app.MapPost("/api/predict", (TicketRequest request,
    PredictionEnginePool<TicketInput, TicketPrediction> pool,
    string[] labels) =>
{
    var input = new TicketInput
    {
        Subject = request.Subject,
        Description = request.Description,
        Priority = request.Priority
    };

    var prediction = pool.Predict(input);

    var confidence = new Dictionary<string, float>();
    for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
    {
        confidence[labels[i]] = prediction.Score[i];
    }

    return Results.Ok(new TicketResponse
    {
        PredictedCategory = prediction.Category,
        Confidence = confidence
    });
});

app.Run();

static TrainResult TrainModel(string contentRoot, ILogger logger)
{
    var dataPath = Path.Combine(contentRoot, "Data", "tickets.csv");
    var modelPath = Path.Combine(contentRoot, "Data", "model.zip");
    var mlContext = new MLContext(seed: 42);

    IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
        dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Text.FeaturizeText(
            "SubjectFeatures", nameof(TicketInput.Subject))
        .Append(mlContext.Transforms.Text.FeaturizeText(
            "DescriptionFeatures", nameof(TicketInput.Description)))
        .Append(mlContext.Transforms.Concatenate("Features",
            "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
        .Append(mlContext.Transforms.Conversion.MapValueToKey("Label",
            nameof(TicketInput.Category)))
        .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
        .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

    logger.LogInformation("Training model from {DataPath}...", dataPath);
    var model = pipeline.Fit(split.TrainSet);

    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

    logger.LogInformation("=== Model Evaluation Metrics ===");
    logger.LogInformation("  MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
    logger.LogInformation("  MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
    logger.LogInformation("  LogLoss:          {LogLoss:F4}", metrics.LogLoss);
    logger.LogInformation("  LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

    // Extract label names from the Score column's slot names
    var scoreMeta = predictions.Schema["Score"].GetSlotNames();
    var labels = new string[scoreMeta.Length];
    for (int i = 0; i < scoreMeta.Length; i++)
        labels[i] = scoreMeta[i].ToString();

    logger.LogInformation("  Labels:           {Labels}", string.Join(", ", labels));

    mlContext.Model.Save(model, data.Schema, modelPath);
    logger.LogInformation("Model saved to {ModelPath}", modelPath);

    return new TrainResult(modelPath, labels);
}

record TrainResult(string ModelPath, string[] Labels);

